import { describe, expect, it } from "vitest";
import { makeUserService } from "../src/userService.js";

describe("makeUserService.getUsers", () => {
  it("does not leak archived users into a non-archived request for the same team", async () => {
    const loadUsers = async ({ includeArchived }) =>
      includeArchived ? ["alice", "bob", "archived-carol"] : ["alice", "bob"];

    const service = makeUserService(loadUsers);

    // An admin view asks for archived users first, populating the cache.
    expect(await service.getUsers({ team: "eng", includeArchived: true })).toEqual([
      "alice",
      "bob",
      "archived-carol",
    ]);

    // The people picker for the same team must NOT see archived users.
    expect(await service.getUsers({ team: "eng", includeArchived: false })).toEqual([
      "alice",
      "bob",
    ]);
  });
});

